        return [0, 0]

    if resources:
        best_r = None
        best_d = 10**9
        for rx, ry in resources:
            d = abs(rx - sx) + abs(ry - sy)
            if d < best_d:
                best_d = d
                best_r = (rx, ry)
        rx, ry = best_r
        best = None
        for dx, dy, nx, ny in valid:
            score = (abs(rx - nx) + abs(ry - ny))
            opp = abs(ox - nx) + abs(oy - ny)
            key = (score, -opp, dx, dy)
            if best is None or key < best[0]:
                best = (key, [dx, dy])
        return best[1]

